const C1='#097C87',C2='#FCA47C',C3='#23CED9',C4='#F9D779',C5='#A1CCA6';
const P5=[C1,C2,C3,C4,C5];
// Extended — darker/lighter variants to fill charts needing more colours
const P=[
  '#097C87','#FCA47C','#23CED9','#F9D779','#A1CCA6',
  '#065e68','#e07a50','#1aabba','#e8c055','#7fb585',
  '#3db8c2','#fdc8a8','#7ae6ee','#fce9a8','#cce5cf',
  '#04434a','#c85a30','#0f8f9e','#d4a830','#4d9e57',
];
function pal(n){return Array.from({length:n},(_,i)=>P[i%P.length]);}

function getStringColor(str, alpha="") {
    if (!str) return '#888888' + alpha;
    const s = str.trim();
    if (s === "OFD" || s.toLowerCase() === "office of faculty development") {
        return '#64748b' + alpha; // Neutral stealth grey
    }
    
    let hash = 0;
    for (let i = 0; i < s.length; i++) {
        hash = s.charCodeAt(i) + ((hash << 5) - hash);
    }
    const index = Math.abs(hash) % P.length;
    return P[index] + alpha;
}

