function formatNameForUI(n){
    let str = String(n||'').trim();
    str = str.replace(/^Dr\.?\s+/i, '').trim();
    let p = str.split(' ');
    if(p.length >= 2) return p[p.length-1]+', '+p.slice(0,p.length-1).join(' ');
    return str;
}

function goToDirectoryName(name) {
    const dBtn = document.querySelector('.tab-btn[onclick*="directory"]');
    if(dBtn) switchTab('directory', dBtn);
    const sIn = document.getElementById('searchInput');
    if(sIn) {
        sIn.value = name;
        filterDir();
    }
}

let rosterMap = {};
function initRoster(){
    const sel = document.getElementById('rosterEventSelect');
    if(!sel) return;
    sel.innerHTML = '<option value="">Select a Session...</option>';
    let options = [];
    for(let sType in sessionsBySeriesRaw){
        sessionsBySeriesRaw[sType].forEach(s => {
            const key = s.topic + "_" + s.date;
            if(!rosterMap[key]) {
                rosterMap[key] = s.comp && s.comp.attendees ? s.comp.attendees : [];
                options.push({key: key, text: s.date + ' | ' + s.topic, date: s.date});
            }
        });
    }
    options.sort((a,b) => b.date.localeCompare(a.date));
    options.forEach(opt => {
        sel.innerHTML += `<option value="${opt.key}">${Math.max(0, opt.text.indexOf('undefined') > -1 ? opt.text.replace('undefined','').trim() : opt.text)}</option>`;
    });
}

function updateRoster(){
    const key = document.getElementById('rosterEventSelect').value;
    const wrap = document.getElementById('rosterWrap');
    const tbody = document.getElementById('rosterBody');
    if(!key || !rosterMap[key] || rosterMap[key].length === 0){
        wrap.style.display = 'none';
        tbody.innerHTML = '';
        return;
    }
    const attendees = rosterMap[key];
    const rows = attendees.map(a => {
        const uin = formatNameForUI(a.name);
        return `<tr>
            <td><a href="#" onclick="goToDirectoryName('${a.name}'); return false;" class="name-cell" style="color:var(--c1d);text-decoration:none;border-bottom:1px dashed var(--c1)">${uin}</a></td>
            <td>${a.rank || ''}</td>
            <td>${a.pos || ''}</td>
            <td>${a.dept || ''}</td>
            <td class="num">${a.duration || 0}</td>
        </tr>`;
    });
    tbody.innerHTML = rows.join('');
    wrap.style.display = 'block';
}

function drilldownToPerson(name) {
    const pSel = document.getElementById('drilldownPerson');
    if (pSel) {
        pSel.value = name;
        document.querySelectorAll('.tab-btn').forEach(b => {
             if(b.textContent.includes('Drilldown')) switchTab('drilldown', b);
        });
        updateDrilldown('person');
    }
}

// ── Tab switch ────────────────────────────────────────────────────────────────
function switchTab(id,btn){
  document.querySelectorAll('.tab-pane').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));
  document.getElementById('tab-'+id).classList.add('active');
  btn.classList.add('active');
  if(id==='activity'   &&!window._aB){buildActivityTab();  window._aB=true;}
  if(id==='engagement' &&!window._eB){buildEngagementTab();window._eB=true;}
  if(id==='drilldown'  &&!window._ddB){
    const pSel = document.getElementById('drilldownPerson');
    if(!pSel.value) {
      let b="", m=-1;
      for(let i=1; i<pSel.options.length; i++){
        let p = pSel.options[i].value;
        let mapP = personSeriesMap[p];
        if(mapP) {
          let t = Object.values(mapP).reduce((A,B)=>A+B,0);
          if(t>m){m=t;b=p;}
        }
      }
      if(b) pSel.value=b;
      else if(pSel.options.length>1) pSel.value=pSel.options[1].value;
    }
    updateDrilldown('dept');
    updateDrilldown('person');
    window._ddB=true;
  }
  if(id==='directory'  &&!window._dB){initDir();           window._dB=true;}
  if(id==='roster' &&!window._rB){initRoster(); window._rB=true;}
}

