let _chartDept=null, _chartPerson=null;

function getSeriesColor(seriesName, alpha="") {
  const idx = seriesAvgLabels.indexOf(seriesName);
  if(idx !== -1) return P5[idx % 5] + alpha;
  return '#888' + alpha;
}

function updateDrilldown(type){
  if(type === 'dept') {
    const d = document.getElementById('drilldownDept').value;
    let map = {};
    if(d === "") {
      for(let dk in deptSeriesMap) {
        for(let s in deptSeriesMap[dk]) {
          map[s] = (map[s] || 0) + deptSeriesMap[dk][s];
        }
      }
    } else {
      map = deptSeriesMap[d] || {};
    }
    const labels = Object.keys(map).sort();
    const data = labels.map(l => map[l]);
    
    if(_chartDept) _chartDept.destroy();
    _chartDept = new Chart(document.getElementById('chartDrilldownDept'),{
      type:'bar',
      data:{labels:labels, datasets:[{
        label:'Sessions Attended', data:data,
        backgroundColor:labels.map(l=>getSeriesColor(l,'cc')), borderColor:labels.map(l=>getSeriesColor(l)), borderWidth:1, borderRadius:4
      }]},
      options:{
        indexAxis:'y', responsive:true, 
        plugins:{
          legend:{display:false},
          title: {display: !!d, text: d || '', font: {size: 14}}
        },
        scales:{x:{beginAtZero:true, grid:{display:false}, ticks:{stepSize:1}}, y:{grid:{display:false}, ticks:{font:{size:10}}}}
      }
    });
  } else if(type === 'person') {
    const p = document.getElementById('drilldownPerson').value;
    const map = personSeriesMap[p] || {};
    const labels = Object.keys(map).sort();
    const data = labels.map(l => map[l]);
    
    if(_chartPerson) _chartPerson.destroy();
    _chartPerson = new Chart(document.getElementById('chartDrilldownPerson'),{
      type:'bar',
      data:{labels:labels, datasets:[{
        label:'Sessions Attended', data:data,
        backgroundColor:labels.map(l=>getSeriesColor(l,'cc')), borderColor:labels.map(l=>getSeriesColor(l)), borderWidth:1, borderRadius:4
      }]},
      options:{
        indexAxis:'y', responsive:true, 
        plugins:{
          legend:{display:false},
          title: {display: !!p, text: p || '', font: {size: 14}}
        },
        scales:{x:{beginAtZero:true, grid:{display:false}, ticks:{stepSize:1}}, y:{grid:{display:false}, ticks:{font:{size:10}}}}
      }
    });

    const tbody = document.getElementById('personDatesBody');
    const wrap = document.getElementById('personDatesWrap');
    if (p && personDatesMap[p] && personDatesMap[p].length > 0) {
      const rows = personDatesMap[p].map(ev => {
          return `<tr>
              <td>${ev.date}</td>
              <td>${ev.series}</td>
              <td>${ev.topic}</td>
              <td class="num">${ev.duration}</td>
          </tr>`;
      });
      tbody.innerHTML = rows.join('');
      wrap.style.display = 'block';
    } else {
      wrap.style.display = 'none';
      tbody.innerHTML = '';
    }
  }
}

