function buildActivityTab(){
  const names=Object.keys(sessionsBySeriesRaw);
  const tabsEl=document.getElementById('seriesTabs');
  names.forEach((name,idx)=>{
    const btn=document.createElement('button');
    btn.className='ser-btn'+(idx===0?' active':'');
    btn.textContent=name;
    btn.onclick=()=>{
      document.querySelectorAll('.ser-btn').forEach(b=>b.classList.remove('active'));
      btn.classList.add('active');
      renderSeries(name,idx);
    };
    tabsEl.appendChild(btn);
  });
  renderSeries(names[0],0);

  renderEngagementMacro();
}

let _macroChart = null;

function renderEngagementMacro(filterKey=null, distType=null) {
  function getSeriesColor(seriesName, alpha="") {
    return getStringColor(seriesName, alpha);
  }

  let data = [];
  let yAxisLabel = 'Attendees';
  
  if (filterKey && distType) {
      yAxisLabel = `${filterKey} Engagement %`;
      const baseline = baselineTotals[distType][filterKey] || 0;
      data = timeline.map(t => {
          let c = 0;
          if (t.comp && t.comp[distType] && t.comp[distType][filterKey]) {
              c = t.comp[distType][filterKey];
          }
          if (baseline > 0) {
              return parseFloat(((c / baseline) * 100).toFixed(1));
          }
          return 0;
      });
  } else {
      data = timelineData;
  }

  if (_macroChart) _macroChart.destroy();
  
  _macroChart = new Chart(document.getElementById('chartTimeline'),{
    type:'bar',
    data:{labels:timelineLabels,datasets:[{
      label: yAxisLabel, data: data,
      backgroundColor:timelineSeries.map(s => getSeriesColor(s, 'bb')),
      borderColor:timelineSeries.map(s => getSeriesColor(s)),
      borderWidth:1,borderRadius:4
    }]},
    options:{
      responsive:true,
      plugins:{
          legend:{display:false},
          title:{display:false,text:'All_Sessions_Chronological_Timeline'},
          tooltip:{
              callbacks:{
                  title:ctx=>timelineDates[ctx[0].dataIndex],
                  label:ctx => ` ${ctx.dataset.label}: ${ctx.raw}` + (filterKey ? '%' : '')
              }
          }
      },
      scales:{
        x:{grid:{display:false},ticks:{font:{size:8.5},maxRotation:45}},
        y:{beginAtZero:true,grid:{display:false},title:{display:true,text:yAxisLabel,font:{size:10}}}
      }
    }
  });
}

