let _actChart=null, _barDistChart=null, _ringDistChart=null, _activeSeriesName=null;

let _activeSeriesIdx = 0;
function renderSeries(name,idx){
  _activeSeriesName = name;
  if(idx !== undefined) _activeSeriesIdx = idx;
  
  const sess=sessionsBySeriesRaw[name];
  const distType = document.getElementById('seriesDistType') ? document.getElementById('seriesDistType').value : 'depts';
  const baseline = baselineTotals[distType] || {};
  
  const vals=sess.map(s=>s.n);
  const avg=vals.length?(vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1):0;
  
  document.getElementById('activityChartTitle').textContent=name+' — Individual Sessions';
  document.getElementById('activityChartSub').textContent=sess.length+' sessions · avg '+avg+' attendees / session';
  document.getElementById('avgLegend').innerHTML='Series average: <span class="avg-pill">'+avg+' / session</span>';
  
  let allKeys = new Set();
  sess.forEach(s => {
      if(s.comp && s.comp[distType]) Object.keys(s.comp[distType]).forEach(k => allKeys.add(k));
  });
  
  let allKeysArr = Array.from(allKeys);
  const ofdIndexAll = allKeysArr.findIndex(k => k === 'OFD' || String(k).toLowerCase() === 'office of faculty development');
  let ofdKeyAll = null;
  if(ofdIndexAll !== -1) {
      ofdKeyAll = allKeysArr.splice(ofdIndexAll, 1)[0];
  }
  allKeysArr.sort();
  if(ofdKeyAll) allKeysArr.unshift(ofdKeyAll);

  let datasets = [];
  allKeysArr.forEach((k, i) => {
      let dataForK = sess.map(s => { return (s.comp && s.comp[distType]) ? (s.comp[distType][k] || 0) : 0; });
      datasets.push({
          label: k,
          data: dataForK,
          backgroundColor: getStringColor(k, 'ee'),
          borderColor: getStringColor(k),
          borderWidth: 1,
          stack: 'Stack 0'
      });
  });
  
  // Also push the total line avg
  datasets.push({label:'Series Avg',data:vals.map(()=>parseFloat(avg)),type:'line',borderColor:'#e07a50',borderWidth:2,borderDash:[6,4],pointRadius:0,fill:false});

  if(_actChart)_actChart.destroy();
  _actChart=new Chart(document.getElementById('chartActivityDetail'),{
    type:'bar',
    data:{
      labels:sess.map(s=>s.label),
      datasets:datasets
    },
    options:{
      responsive:true,
      maintainAspectRatio:false,
      plugins:{
          legend:{position:'top',labels:{usePointStyle:true}},
          title:{display:false,text:'Individual_Sessions_Attendance_Detail'},
          tooltip:{
              callbacks: {
                  label: function(ctx) {
                      if(ctx.dataset.type === 'line') return 'Avg: ' + ctx.raw;
                      let activeCount = ctx.raw;
                      let dept = ctx.dataset.label;
                      
                      // Calculate the total sum of all stacks for this exact session
                      let totalSessionAttendees = 0;
                      ctx.chart.data.datasets.forEach(ds => {
                          if (ds.type !== 'line') {
                              totalSessionAttendees += ds.data[ctx.dataIndex] || 0;
                          }
                      });
                      
                      let p = totalSessionAttendees > 0 ? ((activeCount / totalSessionAttendees)*100).toFixed(1) : 0;
                      return ` ${dept}: ${activeCount} attendees (${p}% of audience)`;
                  }
              }
          }
      },
      scales:{
        x:{stacked:true, grid:{display:false},ticks:{font:{size:9.5},maxRotation:35}},
        y:{
            stacked:true, beginAtZero:true,grid:{display:false},
            title:{display:true,text:'Attendees',font:{size:10}}
        }
      }
    }
  });

  renderSeriesDist();
}

function renderSeriesDist() {
  if(!_activeSeriesName) return;
  const distType = document.getElementById('seriesDistType').value;
  const dist = seriesDistribution[_activeSeriesName] || {'depts':{}, 'ranks':{}, 'positions':{}};
  const typeData = dist[distType] || {};
  
  let keysObj = Object.keys(typeData);
  const ofdIndex = keysObj.findIndex(k => k === 'OFD' || String(k).toLowerCase() === 'office of faculty development');
  let ofdKey = null;
  if(ofdIndex !== -1) {
      ofdKey = keysObj.splice(ofdIndex, 1)[0];
  }
  keysObj.sort((a,b)=>typeData[b]-typeData[a]);
  if(ofdKey) keysObj.unshift(ofdKey);
  
  const keys = keysObj;
  const vals = keys.map(k => typeData[k]);
  
  if(_barDistChart) _barDistChart.destroy();
  if(_ringDistChart) _ringDistChart.destroy();

  // -------- CHART A: AUDIENCE COMPOSITION (Single Stacked Bar) --------
  const compDatasets = keys.map((k, i) => {
      return {
          label: k,
          data: [typeData[k]],
          backgroundColor: getStringColor(k, 'ee'),
          borderColor: getStringColor(k),
          borderWidth: 1
      };
  });

  _barDistChart = new Chart(document.getElementById('chartSeriesComp'),{
    type:'bar',
    data: {
      labels: [_activeSeriesName],
      datasets: compDatasets
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        title:{display:false,text:'Audience_Composition_by_Series'},
        tooltip: {
          callbacks: {
            label: function(ctx) { return ' ' + ctx.dataset.label + ': ' + ctx.raw + ' attendees'; }
          }
        }
      },
      scales: {
        x: { stacked: true, display: false },
        y: { stacked: true, beginAtZero: true, grid: { display:false } }
      }
    }
  });

  // -------- CHART B: ROSTER ENGAGEMENT 100% GAP --------
  const baseline = baselineTotals[distType] || {};
  let penItems = [];

  keys.forEach(k => {
      const active = typeData[k] || 0;
      const total = baseline[k] || 0;
      if (total > 0) {
          let pE = (active / total) * 100;
          penItems.push({key: k, pct: pE});
      }
  });

  const ofdIndexPen = penItems.findIndex(i => i.key === 'OFD' || String(i.key).toLowerCase() === 'office of faculty development');
  let ofdPenObj = null;
  if(ofdIndexPen !== -1) {
      ofdPenObj = penItems.splice(ofdIndexPen, 1)[0];
  }

  penItems.sort((a,b)=>b.pct - a.pct); // Sort highest percentage to lowest
  if(ofdPenObj) penItems.unshift(ofdPenObj);

  const validKeys = penItems.map(i => i.key);
  const engagedPct = penItems.map(i => i.pct.toFixed(1));

  _ringDistChart = new Chart(document.getElementById('chartSeriesPen'), {
    type: 'bar',
    data: {
      labels: validKeys,
      datasets: [
        {
          label: 'Roster Engagement %',
          data: engagedPct,
          backgroundColor: validKeys.map(k => getStringColor(k, 'cc')),
          borderColor: validKeys.map(k => getStringColor(k)),
          borderWidth: 1
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        title:{display:false,text:'Roster_Penetration_by_Series'},
        tooltip: {
          callbacks: {
            label: function(ctx) { 
                const active = typeData[ctx.label] || 0;
                const total = baselineTotals[distType][ctx.label] || 0;
                let rawPct = ((active / total) * 100).toFixed(1);
                return ` Engagement: ${rawPct}% (${active} / ${total} roster members)`;
            }
          }
        }
      },
      scales: {
        x: { ticks: { autoSkip: false, maxRotation: 45, minRotation: 45 }, grid: { display: false } },
        y: { max: 100, beginAtZero: true, grid: { display: false } }
      },
      onClick: (evt, activeElements) => {
          if (activeElements && activeElements.length > 0) {
              const idx = activeElements[0].index;
              const selectedFilter = validKeys[idx];
              // Fire the interactive hook
              renderEngagementMacro(selectedFilter, distType);
          }
      }
    }
  });
}

