// ── DIRECTORY ─────────────────────────────────────────────────────────────────
let _sC=6,_sD=-1;
function initDir(){updateDirCount();}
function filterDir(){
  const q=document.getElementById('searchInput').value.toLowerCase();
  const dept=document.getElementById('deptFilter').value;
  const div=document.getElementById('divisionFilter').value;
  const pos=document.getElementById('posFilter').value;
  const rank=document.getElementById('rankFilter').value;
  let shown=0;
  document.querySelectorAll('#dirBody tr').forEach(tr=>{
    const m=(!q||tr.textContent.toLowerCase().includes(q))&&
            (!dept||tr.dataset.dept===dept)&&
            (!div||tr.dataset.division===div)&&
            (!pos||tr.dataset.pos===pos)&&
            (!rank||tr.dataset.rank===rank);
    tr.style.display=m?'':'none';
    if(m)shown++;
  });
  document.getElementById('dirCount').textContent=shown+' shown';
}
function updateDirCount(){
  document.getElementById('dirCount').textContent=document.querySelectorAll('#dirBody tr').length+' people';
}
function sortDir(col){
  if(_sC===col){_sD*=-1;}else{_sC=col;_sD=(col===8||col===9)?-1:1;}
  document.querySelectorAll('thead th').forEach(th=>th.classList.remove('sorted-asc','sorted-desc'));
  document.querySelectorAll('thead th')[col].classList.add(_sD===1?'sorted-asc':'sorted-desc');
  const tbody=document.getElementById('dirBody');
  Array.from(tbody.querySelectorAll('tr')).sort((a,b)=>{
    let av=a.cells[col]?a.cells[col].textContent.trim():'';
    let bv=b.cells[col]?b.cells[col].textContent.trim():'';
    if(col===8||col===9){av=parseFloat(av)||0;bv=parseFloat(bv)||0;return _sD*(av-bv);}
    return _sD*av.localeCompare(bv);
  }).forEach(r=>tbody.appendChild(r));
}
function addExportButtons(){
  document.querySelectorAll('.chart-card').forEach(card=>{
    const canvas=card.querySelector('canvas');
    if(!canvas)return;
    const cid=canvas.id;
    const bar=document.createElement('div');
    bar.className='export-bar';
    bar.innerHTML=`<button onclick="downloadChartImage('${cid}')" class="export-btn" title="Download Image">PNG image</button> <button onclick="downloadChartCSV('${cid}')" onmouseover="showCSVPreview(event, '${cid}')" onmouseout="hideCSVPreview()" onmousemove="if(document.getElementById('csv-preview-tooltip')){document.getElementById('csv-preview-tooltip').style.left=(event.pageX - Math.min(300, event.pageX - 10))+'px';document.getElementById('csv-preview-tooltip').style.top=(event.pageY+24)+'px';}" class="export-btn" title="Download Data">CSV dataset</button>`;
    canvas.parentNode.insertBefore(bar,canvas);
  });
}
function downloadChartImage(cid){
  const canvas=document.getElementById(cid);
  if(!canvas)return;
  const chart=Chart.getChart(cid);
  let prefix = cid;
  if(chart && chart.config.options.plugins && chart.config.options.plugins.title && chart.config.options.plugins.title.display){
      prefix = chart.config.options.plugins.title.text.replace(/[^a-zA-Z0-9]/g, '_');
  }
  const link=document.createElement('a');
  link.download=prefix+'_export.png';
  const bgCanvas = document.createElement('canvas'); // Pre-fill background white
  bgCanvas.width=canvas.width; bgCanvas.height=canvas.height;
  const ctx = bgCanvas.getContext('2d');
  ctx.fillStyle='#ffffff'; ctx.fillRect(0,0,bgCanvas.width,bgCanvas.height);
  ctx.drawImage(canvas,0,0);
  link.href=bgCanvas.toDataURL('image/png');
  link.click();
}
function generateChartCSV(cid){
  const chart=Chart.getChart(cid);
  if(!chart)return "";
  
  let csv = "";
  
  // 1. Avg Attendance Graph -> Use Raw Series Array
  if(cid === 'chartSeriesAvg' && typeof sessionsBySeriesRaw !== 'undefined') {
    const seriesNames = Object.keys(sessionsBySeriesRaw);
    csv += seriesNames.map(s => `"${s}"`).join(",") + "\n";
    
    // Find the max number of sessions
    let maxLen = 0;
    seriesNames.forEach(s => {
      if(sessionsBySeriesRaw[s].length > maxLen) maxLen = sessionsBySeriesRaw[s].length;
    });
    
    for(let i=0; i<maxLen; i++) {
        let row = [];
        seriesNames.forEach(s => {
            const sess = sessionsBySeriesRaw[s][i];
            row.push(sess ? sess.n : "");
        });
        csv += row.join(",") + "\n";
    }
  }
  // 2. Scatter/Bubble Charts -> Export X, Y, Label
  else if (chart.config.type === 'bubble' || chart.config.type === 'scatter') {
    // Collect all data points
    csv += `"Dataset","Label","X","Y","Radius (if applicable)"\n`;
    chart.config.data.datasets.forEach(ds => {
      ds.data.forEach(pt => {
        let x = pt.x !== undefined ? pt.x : '';
        let y = pt.y !== undefined ? pt.y : '';
        let r = pt.r !== undefined ? pt.r : '';
        // pt might have name/dept embedded if we attached it
        let name = pt.name || pt.dept || ds.label || '';
        csv += `"${ds.label}","${name}",${x},${y},${r}\n`;
      });
    });
  }
  // 3. Standard Charts (Bar, Pie, Line) -> Transpose to Columns (Prism format)
  else {
    let titleStr = "";
    if(chart.config.options.plugins && chart.config.options.plugins.title && chart.config.options.plugins.title.display) {
        titleStr = chart.config.options.plugins.title.text;
    }
    if(titleStr) csv += `"Dataset","${titleStr}"\n`;

    const labels = chart.config.data.labels || [];
    // Header row = Categories
    csv += labels.map(l => `"${l}"`).join(",") + "\n";
    
    // Data rows
    chart.config.data.datasets.forEach(ds => {
      let row = [];
      for(let i=0; i<labels.length; i++) {
         let val = ds.data[i];
         row.push(val === undefined || val === null ? "" : val);
      }
      csv += row.join(",") + "\n";
    });
  }
  return csv;
}

function downloadChartCSV(cid){
  const csv = generateChartCSV(cid);
  if(!csv) return;
  const chart=Chart.getChart(cid);
  let prefix = cid;
  if(chart && chart.config.options.plugins && chart.config.options.plugins.title && chart.config.options.plugins.title.display){
      prefix = chart.config.options.plugins.title.text.replace(/[^a-zA-Z0-9]/g, '_');
  }
  const blob=new Blob([csv],{type:'text/csv;charset=utf-8;'});
  const link=document.createElement('a');
  link.setAttribute('href',URL.createObjectURL(blob));
  link.setAttribute('download',prefix+'_data.csv');
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
}

function showCSVPreview(evt, cid) {
    const csv = generateChartCSV(cid);
    if (!csv) return;
    const lines = csv.split('\n').filter(l => l.trim().length > 0).slice(0, 6);
    let previewHtml = "<strong style='display:block; margin-bottom:6px;'>Data Preview (first 5 rows)</strong><table style='font-size:0.7rem; border-collapse: collapse; min-width: 200px;'>";
    lines.forEach((line, i) => {
        const cells = line.split(',');
        previewHtml += "<tr>" + cells.map(c => `<${i===0?'th':'td'} style='border:1px solid #d4eaec; padding:3px 6px; max-width:90px; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;'>${c.replace(/"/g,'')}</${i===0?'th':'td'}>`).join('') + "</tr>";
    });
    previewHtml += "</table><div style='font-size:0.65rem; color:#888; margin-top:6px;'><i>Click button to download full dataset.</i></div>";
    
    let tooltip = document.getElementById('csv-preview-tooltip');
    if(!tooltip) {
        tooltip = document.createElement('div');
        tooltip.id = 'csv-preview-tooltip';
        tooltip.style.position = 'absolute';
        tooltip.style.background = '#fff';
        tooltip.style.border = '2px solid #097C87';
        tooltip.style.padding = '12px';
        tooltip.style.borderRadius = '8px';
        tooltip.style.boxShadow = '0 6px 16px rgba(0,0,0,0.18)';
        tooltip.style.zIndex = '9999';
        tooltip.style.pointerEvents = 'none';
        tooltip.style.color = '#0d2e32';
        document.body.appendChild(tooltip);
    }
    tooltip.innerHTML = previewHtml;
    tooltip.style.left = (evt.pageX - Math.min(300, evt.pageX - 10)) + 'px';
    tooltip.style.top = (evt.pageY + 24) + 'px';
    tooltip.style.display = 'block';
}

function hideCSVPreview() {
    const tooltip = document.getElementById('csv-preview-tooltip');
    if (tooltip) tooltip.style.display = 'none';
}
window.addEventListener('DOMContentLoaded',()=>{sortDir(6);updateDirCount();addExportButtons();});
